import React, { useState, useEffect } from 'react';
import JSZip from 'jszip';
import './App.css';

const logoImg = require('./WhatsApp Image 2026-07-20 at 9.49.24 PM.jpeg');

function App() {
  const [activeTab, setActiveTab] = useState('home');
  const [zipImages, setZipImages] = useState([]);
  const [isLoadingZip, setIsLoadingZip] = useState(true);

  // Automatically load & extract catalog.zip from the public folder on start
  useEffect(() => {
    async function loadCatalogZip() {
      try {
        const response = await fetch('/catalog.zip');
        if (!response.ok) {
          throw new Error('ZIP file not found in public/ directory');
        }
        const blob = await response.blob();
        const zip = new JSZip();
        const zipContent = await zip.loadAsync(blob);
        const imagePromises = [];

        zipContent.forEach((relativePath, zipEntry) => {
          if (!zipEntry.dir && /\.(png|jpe?g|svg|webp|gif)$/i.test(zipEntry.name)) {
            const promise = zipEntry.async('blob').then((imgBlob) => ({
              name: zipEntry.name,
              url: URL.createObjectURL(imgBlob),
            }));
            imagePromises.push(promise);
          }
        });

        const extractedImages = await Promise.all(imagePromises);
        setZipImages(extractedImages);
      } catch (err) {
        console.log('Ensure catalog.zip exists in public folder.', err);
      } finally {
        setIsLoadingZip(false);
      }
    }

    loadCatalogZip();
  }, []);

  return (
    <div className="app-container" style={{ minHeight: '100vh', background: '#0a0a0a', color: '#fff' }}>
      
      {/* 1. HEADER & NAVIGATION */}
      <header className="navbar" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '15px 40px', borderBottom: '1px solid #d4af37' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img src={logoImg} alt="Jillu Curtains Logo" style={{ height: '50px' }} />
          <span className="gold-text" style={{ fontSize: '1.3rem', fontWeight: 'bold' }}>JILLU CURTAINS</span>
        </div>
        <ul className="nav-links" style={{ display: 'flex', listStyle: 'none', gap: '25px', cursor: 'pointer' }}>
          {['home', 'about', 'services', 'gallery', 'contact'].map((tab) => (
            <li 
              key={tab} 
              className={activeTab === tab ? 'active' : ''} 
              style={{ color: activeTab === tab ? '#d4af37' : '#aaa', textTransform: 'uppercase', fontWeight: 'bold' }}
              onClick={() => setActiveTab(tab)}
            >
              {tab}
            </li>
          ))}
        </ul>
      </header>

      {/* 2. DYNAMIC PAGE CONTENT */}
      <main className="page-wrapper" style={{ padding: '40px 20px', maxWidth: '1100px', margin: '0 auto' }}>
        {activeTab === 'home' && <HomePage setActiveTab={setActiveTab} zipImages={zipImages} isLoading={isLoadingZip} />}
        {activeTab === 'about' && <AboutPage />}
        {activeTab === 'services' && <ServicesPage />}
        {activeTab === 'gallery' && <GalleryPage zipImages={zipImages} isLoading={isLoadingZip} />}
        {activeTab === 'contact' && <ContactPage />}
      </main>

      {/* 3. FOOTER */}
      <footer style={{ borderTop: '1px solid #222', padding: '30px 20px', textAlign: 'center', marginTop: '50px' }}>
        <img src={logoImg} alt="Jillu Curtains" style={{ width: '100px', marginBottom: '10px' }} />
        <p style={{ color: '#d4af37', fontSize: '0.9rem' }}>JILLU CURTAINS — WINDOW DRESSING SOLUTIONS</p>
        <p style={{ color: '#666', fontSize: '0.8rem', marginTop: '10px' }}>© 2026 Jillu Curtains. All Rights Reserved.</p>
      </footer>
    </div>
  );
}

/* --- HOME PAGE --- */
const HomePage = ({ setActiveTab, zipImages, isLoading }) => (
  <div style={{ textAlign: 'center', padding: '40px 0' }}>
    <h1 className="gold-text" style={{ fontSize: '2.8rem', marginBottom: '10px' }}>Elegance for Every Window</h1>
    <p style={{ color: '#aaa', fontSize: '1.1rem', marginBottom: '30px' }}>Custom Drapery, Blinds & Premium Window Styling Solutions</p>
    <button className="btn-gold" style={{ padding: '12px 30px', fontSize: '1rem', cursor: 'pointer' }} onClick={() => setActiveTab('gallery')}>
      View Our Portfolio ({zipImages.length} Designs)
    </button>

    <div style={{ marginTop: '60px' }}>
      <h2 className="gold-text" style={{ marginBottom: '20px' }}>Featured Collection Preview</h2>
      {isLoading ? (
        <p style={{ color: '#d4af37' }}>Loading Catalog Archive...</p>
      ) : zipImages.length > 0 ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '20px' }}>
          {zipImages.slice(0, 4).map((img, idx) => (
            <div key={idx} style={{ background: '#141414', border: '1px solid #333', borderRadius: '8px', padding: '10px' }}>
              <img src={img.url} alt={img.name} style={{ width: '100%', height: '180px', objectFit: 'cover', borderRadius: '6px' }} />
            </div>
          ))}
        </div>
      ) : (
        <p style={{ color: '#888' }}>Place <code>catalog.zip</code> inside <code>client/public/</code> to automatically display portfolio photos.</p>
      )}
    </div>
  </div>
);

/* --- ABOUT PAGE --- */
const AboutPage = () => (
  <div style={{ padding: '20px 0' }}>
    <h1 className="gold-text" style={{ marginBottom: '20px' }}>About Jillu Curtains</h1>
    <p style={{ color: '#ccc', lineHeight: '1.8', fontSize: '1.05rem' }}>
      Jillu Curtains is a premier provider of high-end window dressing solutions. We specialize in custom hand-stitched drapes, motorized blinds, and luxury fabric installations designed to complement modern and classic interiors alike.
    </p>
  </div>
);

/* --- SERVICES PAGE --- */
const ServicesPage = () => (
  <div style={{ padding: '20px 0' }}>
    <h1 className="gold-text" style={{ marginBottom: '20px' }}>Our Services</h1>
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px', marginTop: '20px' }}>
      <div style={{ background: '#141414', border: '1px solid #333', padding: '20px', borderRadius: '8px' }}>
        <h3 className="gold-text">In-Home Consultation</h3>
        <p style={{ color: '#aaa', marginTop: '10px' }}>Expert measurement and fabric recommendations tailored to your space.</p>
      </div>
      <div style={{ background: '#141414', border: '1px solid #333', padding: '20px', borderRadius: '8px' }}>
        <h3 className="gold-text">Custom Tailoring</h3>
        <p style={{ color: '#aaa', marginTop: '10px' }}>Bespoke curtain crafting with precision stitching and premium linings.</p>
      </div>
      <div style={{ background: '#141414', border: '1px solid #333', padding: '20px', borderRadius: '8px' }}>
        <h3 className="gold-text">Motorized & Smart Blinds</h3>
        <p style={{ color: '#aaa', marginTop: '10px' }}>Automated window treatments integrated with home automation systems.</p>
      </div>
    </div>
  </div>
);

/* --- GALLERY PAGE (Auto-Extracted Archive) --- */
const GalleryPage = ({ zipImages, isLoading }) => (
  <div style={{ padding: '20px 0' }}>
    <h1 className="gold-text" style={{ marginBottom: '10px' }}>Jillu Curtains Catalog Portfolio</h1>
    <p style={{ color: '#aaa', marginBottom: '30px' }}>Automatically unpacked from <code>catalog.zip</code> archive</p>

    {isLoading ? (
      <p style={{ color: '#d4af37', fontSize: '1.2rem' }}>Extracting archive contents...</p>
    ) : zipImages.length > 0 ? (
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
        {zipImages.map((img, idx) => (
          <div key={idx} style={{ background: '#141414', border: '1px solid #d4af37', borderRadius: '8px', padding: '10px' }}>
            <img src={img.url} alt={img.name} style={{ width: '100%', height: '220px', objectFit: 'cover', borderRadius: '6px' }} />
            <p style={{ color: '#888', fontSize: '0.8rem', marginTop: '10px', textAlign: 'center', wordBreak: 'break-all' }}>
              {img.name}
            </p>
          </div>
        ))}
      </div>
    ) : (
      <div style={{ background: '#141414', border: '1px dashed #d4af37', padding: '30px', textAlign: 'center', borderRadius: '8px' }}>
        <p style={{ color: '#ccc' }}>No images found. Make sure your file is located at <code>client/public/catalog.zip</code>.</p>
      </div>
    )}
  </div>
);

/* --- CONTACT PAGE --- */
const ContactPage = () => (
  <div style={{ padding: '20px 0', maxWidth: '600px', margin: '0 auto' }}>
    <h1 className="gold-text" style={{ marginBottom: '20px', textAlign: 'center' }}>Contact Jillu Curtains</h1>
    <form style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
      <input type="text" placeholder="Your Name" style={{ padding: '12px', background: '#141414', border: '1px solid #333', color: '#fff', borderRadius: '4px' }} />
      <input type="email" placeholder="Your Email" style={{ padding: '12px', background: '#141414', border: '1px solid #333', color: '#fff', borderRadius: '4px' }} />
      <textarea placeholder="Tell us about your window project..." rows="5" style={{ padding: '12px', background: '#141414', border: '1px solid #333', color: '#fff', borderRadius: '4px' }}></textarea>
      <button type="button" className="btn-gold" style={{ padding: '12px', cursor: 'pointer', fontWeight: 'bold' }}>Send Inquiry</button>
    </form>
  </div>
);

export default App;
